/* cotTruyen q15 (54 chương) — engine-API cotTruyen */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q15"]=window.__LIBQ["tien-nghich"]["q15"]||{};window.__LIBQ["tien-nghich"]["q15"]["cotTruyen"]=[{"chuong":1579,"tieuDe":"Tê Thiên","tomTat":"Vương Lâm dung hợp thân thể với đầu lâu Đạo Cổ Diệp Mịch, hóa thành mắt trái bị mất khiến đầu lâu đầy đủ, rồi đối đầu con trai Diệp Mịch. Va chạm lần đầu, hư ảnh tam tộc cổ của đối thủ sụp đổ nhưng Vương Lâm cũng bị thương nặng ở mi tâm, hai mắt chảy huyết lệ. Vương Lâm dùng Thanh Quang Thuẫn kích hoạt Mộng Hồi Viễn Cổ đã hòa Mộng đạo, kéo tinh không về viễn cổ hiện ba nghìn thân ảnh tam tộc cổ. Con trai Diệp Mịch thi triển thuật Tê Thiên — thần thông cực mạnh do Đạo Cổ Diệp Mịch truyền thừa, lấy vạn vật làm trời dùng hai tay cổ tộc xé trời, xuyên phá Mộng Hồi Viễn Cổ. Vương Lâm dùng Nhân Quả Ấn và Sinh Tử Ấn chống trả nhưng thân thể vẫn bị xé rách từ mi tâm tới bụng, da thịt lộ xương cốt bắt đầu vỡ vụn. Con trai Diệp Mịch rơi vào trạng thái điên cuồng bất chấp sinh tử, chỉ muốn xé tan Vương Lâm, trận chiến chưa phân thắng bại."},{"chuong":1580,"tieuDe":"Một Năm","tomTat":"Trong tình thế xương đầu nứt, lồng ngực rách, Vương Lâm dung hợp Mộng đạo thuật với Mộng hồi viễn cổ của Thanh Quang Thuẫn, trở thành chúa tể giấc mộng, biến toàn bộ thiên địa thành đôi mắt khổng lồ của mình. Con trai Diệp Mịch bị nghiền nát trong mộng, mộng tỉnh vẫn mê mang, bị Vương Lâm dùng huyết kiếm chém đôi; thân thể hóa tám giọt máu tím nhập vào mi tâm Vương Lâm. Vương Lâm bị thương cực nặng, vào Vô Danh Chuyển Luân trận chữa thương. Mấy vạn tu sĩ giới ngoại cùng năm toàn năng nhân cơ hội tấn công trận pháp, Vương Lâm nén thương kích hoạt đại trận hóa bánh xe khổng lồ nghiền nát kẻ địch. Chưởng Tôn xuất hiện, bị Vương Lâm kéo cung Lý Quảng uy hiếp, trầm mặc rồi rút lui. Chín tháng trôi qua không ai dám tới, Tây Tử Phượng ấm rượu chờ nhưng Vương Lâm không uống. Hết một năm, Tây Tử Phượng thần sắc phức tạp rời đi, bên cạnh Vương Lâm chỉ còn nữ tử áo hồng."},{"chuong":1581,"tieuDe":"Lý Thiến Mai Gầy Gò","tomTat":"Sau hơn một năm chữa thương từ thuật Tê thiên, Vương Lâm mở mắt tỉnh dậy bên cạnh nữ tử áo hồng. Hắn nhận ra nàng chính là Hồng Điệp nhờ thông tin Chu Vũ Thái phát hiện trận pháp chứa tóc nàng ở Tuyết Vực quốc. Hai người hàn huyên ba ngày, ôn lại chuyện cũ từ Vũ Tiên Giới, Chu Tước Tinh, Chu Tước mạc cho tới chiến tranh La Thiên; Hồng Điệp bộc lộ kiêu ngạo đã bị năm tháng mài giũa và có tình cảm không rõ ràng với Vương Lâm. Tây Tử Phượng đã rời đi tới Thanh Linh tinh tìm đệ tử Tạ Thanh, để lại bầu rượu. Vương Lâm tiếp tục chữa thương chín tháng. Lam Mộng Đạo Tôn và Lý Thiến Mai xuất hiện — Lý Thiến Mai gầy đi rất nhiều, trí nhớ đã thức tỉnh hoàn toàn, nước mắt rơi khi nghe Vương Lâm nói nàng gầy đi nhiều quá. Lam Mộng thừa nhận nhìn lầm Vương Lâm, đề nghị liên minh hôn nhân: đưa ngũ phi để được làm con rể, Lam Ti Tộc gia nhập giới nội, Lam Mộng sẽ quét sạch đường phía trước cho Vương Lâm."},{"chuong":1582,"tieuDe":"Hai Năm Lại Sáu Tháng","tomTat":"Ngày cuối năm thứ hai, Hồng Điệp từ biệt Vương Lâm để trở về chỗ Mộc Băng Mi. Trước khi đi nàng tiết lộ sư tôn từng gặp đại nho họ Vương — người đặt tên cho nàng — khiến Vương Lâm chấn động mãnh liệt, hoài nghi ranh giới thật–giả của giấc mộng bổn nguyên. Hồng Điệp hỏi về Thanh Thủy rồi nghe kể nữ nhi duy nhất của Thanh Thủy đã luân hồi, trên vai trái có thai ký màu hồng không tiêu tán, nàng lập tức tái nhợt lao về La Thiên muốn gặp Thanh Thủy. Mộc Băng Mi tới bình thản ngồi bên cạnh Vương Lâm. Tới tháng thứ sáu năm thứ ba Vương Lâm tỉnh dậy, trả lời Lam Mộng Đạo Tôn rằng mình đã có thê tử, gián tiếp từ chối hôn sự. Lam Mộng tiết lộ thê tử bị ngũ phi đoạt xá, hồn phách dung hợp không thể tách, tuyên bố không đánh Vương Lâm nữa và sẵn lòng liên thủ, đồng thời hé lộ tu vi Không Huyền đỉnh phong. Ba kẻ địch Diệu Âm đạo tôn, Cửu Thiên ma tôn, Đại Hoang Thượng Nhân được Chưởng Tôn cứu khỏi cổ mộ lao tới tấn công, Lam Mộng chủ động chặn cả ba bằng khí tức đỉnh phong khiến chúng kiêng kỵ."},{"chuong":1583,"tieuDe":"Hay Là Tiếp Nhận Đi","tomTat":"Vương Lâm ngồi trong Vô Danh Chuyển Luân trận dưỡng thương đã hai năm, hồi phục hơn phân nửa, tiếp tục dung hợp tám giọt máu cổ đạo và nghiên cứu thuật Tê Thiên. Bên ngoài, Lam Mộng Đạo Tôn một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày: Diệu Âm trọng thương rớt xuống Không Linh trăm năm không phục, Cửu Thiên mất hương hỏa giới tâm thần tổn thương, Đại Hoang bỏ chạy sống không quá mười năm. Lam Mộng Đạo Tôn tự xưng là một trong thái cổ ngũ tôn, tuyên bố mọi việc đều vì con gái và không tham gia cuộc chiến giới nội giới ngoại, đặt điều kiện cuối cho Vương Lâm về quan hệ với Lý Thiến Mai. Vương Lâm ban đầu tuyên bố cả đời chỉ có một thê tử, nhưng khi Lý Thiến Mai xin lại bức tranh Tương Vong Vu Giang Hồ và nói lời đoạn tuyệt, hắn nắm chặt bức tranh rồi hủy nó, tuyên bố từ nay Lý Thiến Mai là nữ nhân của hắn, đồng thời khẳng định Lý Mộ Uyển vẫn là thê tử. Mộc Băng Mi chứng kiến cảnh này mi tâm mơ hồ đau đớn."},{"chuong":1584,"tieuDe":"Gặp Lại Văn Thú","tomTat":"Lý Thiến Mai cùng phụ thân Lam Mộng Đạo Tôn (Không Huyền đỉnh phong) mang ngũ phi trở về Lam Ti tộc, dự định lần sau mang cả tộc vào giới nội lập tân tộc. Sau gần một năm im lặng trong Vô Danh Chuyển Luân trận, Mộc Băng Mi nói câu duy nhất — Bảo trọng — rồi xoay người về Côn Hư trong tâm trạng cô độc tuyệt vọng. Chỉ còn một tháng trước khi tứ đại chiến tướng ra khỏi viễn cổ tiên vực, Vương Lâm điểm vào mi tâm tách phân thân tu sĩ (Không Linh trung kỳ) ra khỏi bổn tôn (Cổ Thần, Cổ Yêu, Cổ Ma). Bổn tôn ở lại giữ Vô Danh Chuyển Luân trận, phân thân bước vào tinh không giới nội thực hiện kế hoạch ngưng tụ tứ đại tiên giới dung hợp thành tân tiên giới. Phân thân đầu tiên tới Phong Tiên giới ở Vân Hải tinh vực, nơi hai đàn Văn thú trên vạn con đang chém giết nhau. Con Văn thú khổng lồ màu vàng thân trăm vạn trượng — bị thất lạc trăm năm — khi cảm nhận khí tức chủ nhân liền kích động điên cuồng lao tới, Vương Lâm quay đầu lộ nụ cười vui vẻ."},{"chuong":1585,"tieuDe":"Phát Hiện Ngoài Ý Muốn","tomTat":"Phân thân Vương Lâm trong Phong Tiên giới hội ngộ Văn vương trăm trượng dẫn đầu đàn trên vạn Văn thú, nhận ra nó đã tiến hóa mạnh mẽ, tu vi tiếp cận bước thứ ba chỉ còn kém một bước lột xác. Văn vương dẫn Vương Lâm vào vùng sâu sương mù, nơi pho tượng hình người từng thấy năm xưa đã biến mất và có thi thể Văn thú ngàn trượng bước thứ ba nằm trên đại lục. Vương Lâm phát hiện thi thể bị giết bằng ba ngón tay xuyên thấu vào cổ, khí tức lưu lại khiến hắn cảm thấy mơ hồ quen thuộc. Hắn dùng ngọc giản thí nghiệm so sánh vết gãy, kết luận cái khe khổng lồ đã bị xé mở hai lần — lần đầu bởi kẻ bí ẩn, lần hai khi Phong Tiên giới sụp đổ. Theo Văn vương vào bên trong khe, Vương Lâm phát hiện không gian tràn ngập huỳnh quang chứa hàng trăm vạn trứng Văn thú các kích cỡ, là nguồn cơ duyên giúp Văn vương tiến hóa. Khi tản thần thức bao phủ toàn bộ không gian, hắn kinh ngạc lùi lại mấy bước ngẩng phắt đầu — phát hiện điều gì đó chấn động nhưng chương kết thúc ở đây."},{"chuong":1586,"tieuDe":"Mũi Kiếm Tiến Vào Tiên Cương","tomTat":"Vương Lâm khám phá thông đạo bí ẩn trong động phủ, phát hiện cửa đá khổng lồ có lá phù phong ấn hai chiều ở cuối. Lần đầu xuất nguyên thần dung hợp huyết kiếm tiếp cận nhưng bị lực bài xích đẩy lui ở mười trượng cuối. Lần hai bạo phát toàn lực, triệu lục đại bổn nguyên — lôi, hỏa, sinh, tử, nhân, quả, tam đại hư, sát lục — ngưng tụ trong huyết kiếm, xuyên qua phong ấn đâm sâu ba thước vào cửa đá, cảm nhận được khí tức Tiên Cương đại lục bên kia. Mũi kiếm lộ ra ba tấc phía Tiên Cương, xuyên qua Đông Đan chung — chí bảo của Quy Nhất tông — tỏa huyết quang kinh thiên. Chưởng môn phân tông Quy Nhất tông cùng tám tu sĩ bay tới, nhận ra đó là kiếm của Diệp Mịch, xác nhận lời đồn Diệp Mịch bị Thất Đạo Tông dẫn vào động phủ. Hé lộ Thất Thải Tiên Tôn từ bỏ đạo lữ phong tỏa Thất Đạo Tông để đoạt bảo vật, Mã sư huynh của Quy Nhất tông đã dùng chí bảo mở thông đạo thông tới động phủ. Vương Lâm bị đẩy lui, rút ra ngoài an toàn, ngộ ra bên ngoài cửa đá chính là Tiên Cương đại lục."},{"chuong":1587,"tieuDe":"Người Từ Bên Ngoài Tới","tomTat":"Vương Lâm đứng trước cánh cửa đá trong thông đạo đầy trứng Văn thú, nhận ra đây không phải đại môn động phủ Thất Thải Tiên Tôn mà là thông đạo bị tu sĩ từ bên ngoài mở ra để xâm nhập. Hắn liên kết nhiều manh mối — nhóm tu sĩ thần bí từng xuất hiện ở Thiểm Lôi tộc với trang phục kỳ dị, pháp bảo Côn Cực Tiên, thủ lĩnh giống hệt Nạp Đa — suy ra bọn họ chính là tu sĩ từ một tông phái trên Tiên Cương đại lục, có thể vẫn đang ở Ngũ Hành tinh chờ đợi. Vương Lâm thu toàn bộ hàng trăm vạn trứng Văn thú vào không gian trữ vật, phong ấn khe nứt thông đạo bằng cấm chế và cổ Tức Diệp. Sau đó hắn dùng tu vi Không Linh trung kỳ bao trùm toàn bộ Phong Tiên giới, ép các mảnh đại lục vỡ vụn ngưng tụ thành một đại lục hoàn chỉnh, gió lốc sụp đổ, Văn thú run rẩy nằm rạp. Cuối cùng hắn ngồi khoanh chân trên đại lục, dùng nguyên thần dung hợp mặt đất, điều khiển cả Phong Tiên giới bay ra tinh không Vân Hải tinh vực và tiến thẳng về Triệu Hà để tới Thiểm Giới — tiên giới duy nhất hắn chưa từng đi qua."},{"chuong":1588,"tieuDe":"Tiến Bước Nghịch Tiên","tomTat":"Vương Lâm điều khiển Phong Tiên giới rời Vân Hải tinh vực tới Triệu Hà, vào Thiểm Giới khảo sát ba ngày rồi nhận định đã bị hủy diệt không thể cứu vãn, thu cả dải ngân hà làm tầng bảo vệ vờn quanh đại lục. Đưa Phong Tiên giới tới La Thiên Tinh Vực khảo sát Lôi Tiên Giới, thấy đã hoàn toàn bị phế. Khi rời đi, hạt châu Thiên Nghịch tự lóe sáng giúp Vương Lâm nhận biết Chiến lão quỷ đang ẩn thế trong Lôi Tiên Giới nhìn mình, nhưng hắn dấu diếm rời đi. Chiến lão quỷ tự hỏi Vương Lâm có phải là người thứ ba hay không. Tại giao điểm tứ đại tiên giới, Vương Lâm ngưng tụ Tân tiên giới: lấy Phong Tiên giới làm căn cơ, bụi bặm Vũ Giới bành trướng, Thiểm Giới ngân hà bảo vệ phân tiên phàm, Vô Danh Chuyển Luân trận hấp thu Thái cổ Tinh Thần. Phân nguyên thần cùng mấy vạn tu sĩ do Thanh Lâm dẫn đầu thu tinh hồn tứ đại tinh vực dung hợp vào tân tiên giới, thiết lập cơ chế phi thăng cho tu sĩ đột phá Hóa Thần. Vương Lâm tuyên bố từ bỏ danh xưng Phong Tôn, sắp nghịch tiên — thành thì tiên phá, bại thì tử vong, gửi gắm Tư Đồ Nam bố cáo hậu thế rồi cô độc bước đi, mấy vạn tu sĩ vái tiễn."},{"chuong":1589,"tieuDe":"Tiên Long Hiển Đạo","tomTat":"Vào ba ngày cuối cùng của năm thứ ba, bổn tôn Vương Lâm mở mắt bên ngoài Vô Danh Chuyển Luân trận, phân thân bạch y từ giới nội trở về dung hợp vào bổn tôn. Vương Lâm cảm ngộ rằng cường giả chân chính là người hiểu được sự gánh vác, liên hệ hình ảnh phụ thân phàm nhân với con đường tu đạo hơn hai ngàn năm. Quyết định hủy diệt viễn cổ tiên vực giới ngoại và tạo hỗn loạn trước đại chiến, hắn không ẩn giấu khí tức trực tiếp tiến vào Thái Cổ Tinh Thần, thần thức khuếch tán khiến mọi cường giả bừng tỉnh. Chưởng Tôn cảm nhận được nhưng không dám ra tay vì kiêng kỵ cung Lý Quảng. Đạo nhân bảy màu tiết lộ huyết trận đã hoàn thành và đang tính toán vị trí người thứ ba luân hồi vô số lần, đồng thời cho biết chính hắn đã sắp đặt để Chưởng Tôn trao cung Lý Quảng cho Vương Lâm. Tam phi và Thất phi cũng mở mắt cảm nhận sự xuất hiện của Vương Lâm. Vương Lâm dừng lại gần trung tâm Thái Cổ Tinh Thần khoanh chân thổ nạp, vận chuyển giọt máu tiên nhân bất diệt thể đưa khí tức lên đỉnh phong, chờ đợi biến đổi kinh thiên chỉ còn mười hai canh giờ nữa — ngoài hắn chỉ có Thiên Vận Tử ở Triệu Hà tinh vực hơi cảm ứng được. Khi còn ba-bốn canh giờ, mấy trăm tới hơn ngàn tu sĩ mặt vẽ xanh đỏ gào thét khẩu hiệu Tiên Long Hiển Đạo lao tới vị trí Vương Lâm."},{"chuong":1590,"tieuDe":"Một Con Rắn","tomTat":"Trong thế giới động phủ, huyết viêm long từ vùng đất Điên Lạc (từng bị Chu Tước đời hai thả đi và bán đứng cho Vương Lâm) tái xuất sau hơn trăm năm, đã tự lập Tiên Long Đạo với hơn ngàn tu sĩ, sống hưởng thụ trên đài linh thạch ngàn trượng. Khi đoàn Tiên Long Đạo tiến gần khu vực Vương Lâm, thần thức các toàn năng Thái Cổ Tinh Thần ngưng tụ quanh hắn lan tới, khiến viêm long hoảng sợ gần vỡ mật. Nó cuống quít ra lệnh rút lui, tự hạ mình xưng chỉ là một con rắn dài hơi giống rồng. Viêm long bỏ đài linh thạch bay lên định tẩu nhưng Vương Lâm bạch y tóc bạc hiện ra chặn đường. Vì ngốc nghếch, viêm long nhớ Vương Lâm là tiểu tử yếu ớt ngày xưa nên phun hỏa cầu tấn công, nhưng bị Vương Lâm phá tan dễ dàng, thu toàn bộ ngọn lửa vào tay trái. Viêm long run rẩy choáng váng, cuối cùng nhận ra khí tức kinh khủng truyền ra từ thân thể đối phương."},{"chuong":1591,"tieuDe":"Tiểu Hồng","tomTat":"Viêm long thi triển toàn lực tháo chạy nhưng cảm nhận hỏa bổn nguyên của Vương Lâm mạnh hơn rất nhiều, không dám chiến đấu. Vương Lâm sử dụng ấn quyết Chu Tước đời thứ hai kích hoạt ấn ký trên mi tâm viêm long, khiến nó đau đớn kêu thảm rồi đầu hàng. Vương Lâm phát hiện trong thân viêm long ẩn chứa huyết mạch tiên nhân nhờ giọt máu tiên nhân bất diệt thể trên mi tâm. Viêm long xin Vương Lâm phối hợp diễn kịch giữ thể diện trước hơn ngàn môn đồ Tiên Long Tông, tuyên bố Vương Lâm làm phó tông chủ rồi sai họ lui về. Sau đó viêm long khai nhận tên Tiểu Hồng do chủ nhân cũ đặt, xác nhận đến từ Tiên Cương đại lục, theo Liên Đạo Phi cùng một kẻ khác vào Thái Cổ Tinh Thần nhưng bị lừa tới Thất Đạo Tông rồi bị bắt. Vương Lâm chấn động khi nhận ra Tiểu Hồng chính là thú cưỡi của Liên Đạo Phi — người điên năm xưa. Viêm long xác nhận Liên Đạo Phi đã chết. Vương Lâm thu viêm long vào khe trữ vật, bình ổn tâm cảnh trong ba canh giờ cuối cùng trước khi thời hạn ba năm kết thúc rồi mở bừng đôi mắt."},{"chuong":1592,"tieuDe":"Viễn Cổ Tiên Vực Mở Ra","tomTat":"Đúng một trăm năm kể từ khi giới nội-giới ngoại khai chiến, cũng là thời hạn ba năm mà Vương Lâm ước định với tứ đại chiến tướng viễn cổ tiên vực. Tiếng chấn động ầm ầm vang lên từ Côn Hư tinh vực rồi lan ra cả tứ đại tinh vực, uy áp viễn cổ đè xuống khiến tu sĩ phun máu, phàm nhân hôn mê, toàn bộ ánh sáng mất đi. Tinh không vỡ vụn tạo bốn khe nứt khổng lồ từ tứ đại tinh vực, ngưng tụ thành hình chữ thập tại vị trí tân tiên giới. Hơn mười sáu thân ảnh tỏa kim quang bước ra trên cầu thang ánh sáng, tất cả đều có khí tức bước thứ ba nhưng mơ hồ khác biệt với tu sĩ bình thường. Chiến Không Liệt trong Lôi Tiên giới vọt ra Thiểm Lôi tộc, nhận ra đây là viễn cổ tiên vực. Thanh Lâm dẫn Hồng Sam Tử, Nam Vân Tử, Thanh Thủy bay ra tinh không, xưng đệ tử Phong Tôn cung kính bái kiến tiên nhân viễn cổ, nhưng bị phớt lờ hoàn toàn. Đám tiên nhân cười lớn xuyên qua bốn người, lao thẳng về tân tiên giới thôn phệ hương hỏa để giải cơn nghiền vạn cổ, khiến bốn người chấn động. Tư Đồ Nam đứng dưới mặt đất nhìn khe nứt, nhớ lời Vương Lâm, không kính sợ mà chỉ cảm thấy mờ mịt và phức tạp."},{"chuong":1593,"tieuDe":"Cút Ra Mau","tomTat":"Hơn mười viễn cổ tiên nhân phá vỡ ngân hà xâm nhập tân tiên giới, dùng lực lượng huyết mạch trấn áp Thanh Lâm, Hồng Sam Tử, Nam Vân Tử, chỉ Thanh Thủy không bị ảnh hưởng, lao xuyên lốc vàng phản kích. Một tiên nhân hút nữ tu Triệu Hà thành hương hỏa, nhưng đám tiên nhân phát hiện pho tượng Vương Lâm trên ngọn núi trong tiên giới, hoảng sợ nhớ lại uy lực một tiễn ba năm trước. Tư Đồ Nam bóp nát ngọc giản mà Vương Lâm giao ba năm trước, thần thức huyễn hóa thành thân ảnh quát hỏi Chu Tước, Huyền Vũ, Thanh Long, Bạch Hổ về ước định, phát sát lục đuổi toàn bộ tiên nhân ra ngoài. Thanh Long Thánh Hoàng xuất hiện dưới hình dạng lão già, ôm quyền xin lỗi và cam kết giữ giao dịch cũ, viễn cổ tiên vực sẽ không giết tu sĩ giới nội. Viễn cổ tiên vực giới nội mở kéo giới ngoại cũng mở, Vương Lâm bản thể nhận ra liền vọt tới, ý đồ lấy lực lượng hai cung hủy diệt viễn cổ tiên vực giới ngoại khiến Chưởng Tôn kinh hãi gọi là điên cuồng. Tinh không sụp đổ lộ lỗ hổng, đệ tử Thất Đạo Tông nghe lệnh tiên phi bay ra, tuyên bố muốn giết tứ đại chiến tướng và lập lại Thất Đạo Tông. Một tiên nhân lao tới định hút Vương Lâm, nhưng hắn mở mắt phát kim quang từ giọt máu tiên nhân bất diệt thể, huyết mạch tinh thuần cực điểm, trấn áp đối phương khiến hắn hãi hùng hỏi “Ngươi là ai!”"},{"chuong":1594,"tieuDe":"Lực Lượng Hai Cung","tomTat":"Vương Lâm triệu cung Lý Quảng, lần đầu tiên liên tục bắn hai mũi tên. Mũi thứ nhất bành trướng mấy ngàn trượng, xuyên qua hình thần câu diệt, giết sạch hơn mười tiên nhân Thất Đạo Tông vừa bước ra khỏi viễn cổ tiên vực. Mũi thứ hai mang lực hút khổng lồ khiến lỗ hổng thông đạo co rút sụp đổ hoàn toàn, phong ấn viễn cổ tiên vực giới ngoại, đồng thời ngăn hai luồng khí tức mạnh ngang Chưởng Tôn từ bên trong lao ra. Kim quang huyết mạch tiên nhân trong hai mắt Vương Lâm tiêu tán, trán toát mồ hôi. Chưởng Tôn ở cách ngàn vạn dặm cảm nhận được, vui mừng đánh giá Vương Lâm đã dùng hết lực hai cung, lập tức phong ấn toàn bộ Thái Cổ Tinh Thần rồi lao tới truy sát. Thất phi oán hận muốn tự tay giết Vương Lâm, Diệu Âm đạo tôn và Cửu Thiên ma tôn dù thương thế chưa hồi phục cũng gào thét lao tới. Trong khi đó, tứ đại chiến tướng giới nội chứng kiến uy lực, Huyền Vũ phân tích Vương Lâm tâm trí cẩn thận, đoán hắn nhất định có lực bắn ba mũi tên chứ không chỉ hai, bốn người đều đồng ý không nên trêu chọc."},{"chuong":1595,"tieuDe":"Tuyệt Đối Không Sai","tomTat":"Chưởng Tôn chờ đúng thời cơ Vương Lâm bắn xong hai mũi tên hết lực lượng huyết mạch tiên nhân, tu vi huyền kiếp bạo phát xuất hiện trong tinh vực quyết tâm hạ sát. Hắn hồi tưởng toàn bộ quá khứ: ba lần chật vật trước khi gặp Vương Lâm (bị đạo nhân bảy màu bắt bái sư, thua Chiến Không Liệt tại Thái Cổ Tinh Thần, bị trọng thương khi tìm mũi tên Lý Quảng) và năm lần đối đầu Vương Lâm đều thất bại hoặc ngoài ý muốn, sau đó chính thức coi Vương Lâm là khắc tinh. Chưởng Tôn không nói một câu, trực tiếp đánh chưởng ấn trăm trượng. Vương Lâm bình tĩnh nghênh chiến: kích hoạt Cổ Thần tinh điểm và tinh điểm Cổ Yêu, lần đầu thi triển thần thông tự nghĩ ra Tộc Bất Diệt Chỉ (lấy cảm hứng từ tiên nhân bất diệt thể), đồng thời triển khai Thanh Quang Thuẫn, Quang Ảnh Thuẫn và Ngũ Thải hồ điệp. Ngón trỏ đối đầu chưởng ấn bị hủy diệt và tái tạo hơn ngàn lần, thân thể nứt vỡ phun máu, cả ba lớp phòng ngự đều sụp đổ. Vương Lâm chịu tổn thương nghiêm trọng nhưng nói «Còn chưa tới thời cơ» ám chỉ còn hậu thủ."},{"chuong":1596,"tieuDe":"Tuyệt Đối Không Sai","tomTat":"Vương Lâm bị Chưởng Tôn tung chưởng ấn huyền kiếp đánh trọng thương liên tiếp, lần lượt dùng Dịch Linh Ấn, trường thương bảy màu, sáu thanh kiếm bổn nguyên đối kháng đều không đủ sức. Hắn lần đầu thi triển thuật Tê Thiên kết hợp hư ảnh thân thể Đạo Cổ (lần đầu hiện cả thân thể mơ hồ, không chỉ đầu lâu) xé tan chưởng ấn, bản thân bị trọng thương nặng. Vương Lâm hé lộ kế hoạch lớn: hủy viễn cổ tiên vực giới ngoại, làm loạn động phủ, khiến các thế lực mất cân bằng — tất cả chỉ là bước đầu tiên. Khi bốn cường giả (Chưởng Tôn, Thất Phi, Diệu Âm Đạo Tôn, Cửu Thiên Ma Tôn) tụ tập vây sát, Vương Lâm rút cung Lý Quảng bắn mũi tên thứ ba — hoàn toàn vượt ngoài dự liệu của Chưởng Tôn. Mũi tên xuyên phá mọi thần thông, xuyên thân Chưởng Tôn khiến hắn tan xác rồi ngưng tụ sống lại, đạo tâm sụp đổ điên cuồng bỏ trốn. Diệu Âm Đạo Tôn và Cửu Thiên Ma Tôn bị nổ tung thân thể, nguyên thần bị Vương Lâm bắt gọn. Thất Phi nhờ chí bảo phòng thân nên chỉ trọng thương trốn thoát. Cuối chương, vùng tinh vực đột nhiên tràn ngập ánh sáng bảy màu, hình như có một người bí ẩn mang ánh sáng bảy màu tràn tới chiếu rọi cả tinh không."},{"chuong":1597,"tieuDe":"Ước Định Năm Đó","tomTat":"Đạo nhân bảy màu hiện thân trong tinh không Thái Cổ Tinh Thần, Vương Lâm lập tức bóp nát ngọc giản tạo hắc động rút lui. Từ hắc động vươn ra ngọc thủ đệ nhất phi thi triển Thái Ngọc Thất Thủ Ấn đỡ chỉ phong bảy màu, Vương Lâm bị hắc động hút vào thoát đi. Chưởng Tôn và thất phi kinh hãi nhận ra chủ nhân bàn tay chính là đại tỷ — đệ nhất phi. Đạo nhân bảy màu bình thản hóa giải ấn quyết, tuyên bố cung Lý Quảng hoàn thành sứ mạng cần thu hồi rồi biến mất. Vương Lâm tới nơi Phàn San Lộ ẩn náu trong khe sâu Yêu Tông cũ, trên lưng mãnh thú sư tử có sừng. Nàng tiết lộ tên thật Phàn San Lộ, đệ nhất phi Thất Đạo Tông, muội muội Phàn San Mộng — đạo lữ Thất Thải Thiên Tôn, cả hai là đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn phía đông Tiên Cương đại lục. Nàng kể Thất Thải Thiên Tôn năm xưa phản bội tỷ tỷ để đoạt bảo vật liên quan vầng mặt trời thứ chín rồi phong kín Thất Đạo Tông, đề nghị Vương Lâm giết hắn đoạt sơn môn, hứa giúp qua kiếp nạn nhập giới và giới thiệu vào Đại Hồn Môn. Cuối chương cả hai bất ngờ cảm ứng điều bất thường phía sau."},{"chuong":1598,"tieuDe":"Đạo Nhân Bảy Màu Đã Tới","tomTat":"Đạo nhân bảy màu (tự xưng Thất Thải Tiên Tôn) xuất hiện trong tinh không Vân Hải tinh vực, truy sát Vương Lâm và Phàn San Lộ nhằm đoạt cung Lý Quảng. Hắn hừ lạnh tiêu diệt hơn trăm mãnh thú mà Phàn San Lộ dùng huyết tế dụ tới cản đường, sóng âm từ lời nói đánh vào tâm thần khiến Vương Lâm phun máu. Đạo nhân triệu chín hỏa điểu (chín tu chân tinh bị luyện hóa, uy lực vượt Chu Tước) tấn công. Phàn San Lộ thi triển Đại Hồn đạo — Dẫn Hồn Minh, tế hiến hồn tạo trường đao huyết sắc chém chín hỏa điểu; Vương Lâm dùng giọt huyết mạch tiên nhân mà Chưởng Tôn không biết để kéo cung Lý Quảng bắn mũi tên va chạm chín hỏa điểu. Đạo nhân bảy màu phóng tinh thể bảy màu vây khốn hai người, Phàn San Lộ kích hoạt thủ ấn bảy màu kêu gọi tỷ tỷ — một nữ tử giống hệt nàng trong băng sơn Tiên Cương đại lục truyền lực xuyên không gian phá vây. Phàn San Lộ kiệt sức, Vương Lâm ôm nàng na di tới động phủ thuyền tím của nàng, hỏi danh tính thật đạo nhân bảy màu, nàng chỉ đáp mập mờ rồi chương kết thúc."},{"chuong":1599,"tieuDe":"Phàn San Mộng","tomTat":"Phàn San Lộ bất ngờ phát sinh dị biến trên boong thuyền, mi tâm ngưng tụ dòng xoáy bảy màu kèm hàn khí dữ tợn, phía sau hiện khuôn mặt tuyệt mỹ giống hệt nàng nhưng kiều diễm hơn. Vương Lâm tản thần thức khảo sát toàn bộ chiến thuyền, nhận ra cả thuyền do cấm chế tạo thành như trận pháp khổng lồ, nhận diện tứ đại cấm chế và nhiều loại chưa từng thấy, thấy cơ hội đạt cấm chế bổn nguyên. Đạo nhân bảy màu bước ra từ tinh không tấn công thuyền, phá một tầng phòng hộ, nhưng không nhớ vì sao chiến thuyền quen thuộc. Sau dị biến, nữ tử trên thuyền tự xưng Phàn San Mộng — tỷ tỷ của Phàn San Lộ, đạo lữ cũ của Thất Thải Tiên Tôn. Nàng kể lại quá khứ: khi mặt trời thứ chín, Đạo Nhất và Huyền La tranh đoạt bảo vật từ Thái Cổ Thần Cảnh, Thất Thải Tiên Tôn nhờ cơ duyên lấy được mảnh vỡ rồi ám toán nàng chiếm tu vi diệt khẩu. Nhờ mệnh hồn sư tôn giữ nên được cứu sống bằng thuật luân hồi, sau đó mượn pháp lực sư tôn dụ Liên Đạo Phi tới và phối hợp muội muội gây chia rẽ Thất Đạo Tông thành giới nội giới ngoại. Cuối cùng nàng tiết lộ bên trong mảnh vỡ chính là thiên đạo ngày nay."},{"chuong":1600,"tieuDe":"Ba Hồn Bảy Phách","tomTat":"Nữ tử áo trắng kể tiếp trận đại chiến năm xưa: Liên Đạo Phi một mình áp đảo tứ đại chiến tướng và đệ tử Thất Đạo Tông, nhưng Thất Thải Thiên Tôn triệu hồi thiên đạo dùng thuật cắn nuốt thiên đạo, Liên Đạo Phi bị nuốt trọng thương, nhờ tiên nhân bất diệt thể không chết, vẫn ở đâu đó trong thế giới động phủ; thiên đạo cũng chết, chúng sinh không hề hay biết. Nữ tử tiết lộ bí mật ba hồn bảy phách: kim thân Thất Thải Thiên Tôn tan nát hóa ba chủ hồn — hồn thứ nhất nắm thần thông chính là đạo nhân bảy màu chiếm giới ngoại, hồn thứ hai chứa ý cảnh và bổn nguyên chạy trốn, hồn thứ ba nắm trí nhớ và bí mật triệu hoán thiên đạo nhưng đã mất tích trong vô số luân hồi — cùng thất phách cũng luân hồi khắp nơi; ai nuốt hồn thứ ba sẽ dung hợp tất cả trở thành Thất Thải Thiên Tôn mới. Vương Lâm chấn động, suy luận Chiến lão quỷ chính là hồn thứ hai, Thanh Thủy sư huynh là một trong thất phách, tự hỏi bản thân có phải thất phách hay không. Nữ tử đề xuất hai phương pháp hợp tác giết Thất Thải Thiên Tôn, gợi ý Vương Lâm thôn phệ hồn thứ ba rồi nuốt nốt hai hồn và thất phách để trở thành Thất Thải Thiên Tôn hoàn chỉnh, hứa tặng Thất Đạo Tông và giúp người thân Vương Lâm chuyển thế luân hồi vào Tiên Cương. Vương Lâm liên tưởng tới chuyện thánh tổ phù văn tộc bị Thanh Lâm trấn áp, cảnh giác nhận ra mọi lời nữ tử chỉ là đánh lạc hướng có thâm ý riêng, không vội thệ huyết, chuyển hướng hỏi về tế đàn năm xưa."},{"chuong":1601,"tieuDe":"Phản Khách","tomTat":"Đạo nhân bảy màu liên tục tấn công thuyền từ bên ngoài, phá vỡ hơn một nửa tầng sáng phòng hộ. Phàn San Mộng tiết lộ trên thuyền có tế đàn chứa cổ lực ở tầng cuối, đề nghị Vương Lâm dùng ba ngày phá phòng hộ hấp thu truyền thừa để tăng tu vi. Vương Lâm từ chối, nhìn thấu mưu kế của hai chị em Phàn San Mộng cố ý dùng áp lực bên ngoài từ đạo nhân bảy màu để ép hắn trao huyết thệ. Nội tâm Phàn San Mộng bật mí mục đích thật: dùng thệ huyết nhận trợ giúp sư tôn, dẫn động pháp thuật biến Vương Lâm thành con rối để giết Thất Thải Tiên Tôn. Vương Lâm quyết định phản khách vi chủ, dung hợp lực lượng tam tộc cổ hóa hư ảnh Đạo cổ bảo vệ thân, triển khai gần trăm vạn cấm chế ấn chưởng phá vỡ tầng phòng hộ ngoài cùng boong thuyền, lộ ra bản chất boong tàu là cấm chế ngưng tụ mà thành. Phàn San Mộng kinh ngạc nhưng tuyên bố nếu Vương Lâm nghiên cứu ra toàn bộ sẽ tặng luôn thuyền, tin chắc ba ngày không đủ. Vương Lâm bắt đầu phân tích từng ký hiệu cấm chế."},{"chuong":1602,"tieuDe":"Mặt Quỷ Trên Cánh Buồm","tomTat":"Vương Lâm tĩnh tâm nghiên cứu cấm chế trên boong thuyền của Phàn San Mộng. Gió quỷ dị thổi qua cánh buồm khiến mặt quỷ trên đó lộ ánh sáng yêu dị, cười chằm chằm nhìn hắn, khiến hắn bất an nửa ngày mới trấn tĩnh. Hắn dành năm canh giờ nghiên cứu thấu đáo một Cổ Hồn cấm, từ đó hoàn toàn lĩnh ngộ loại cấm chế thứ tư trong tứ đại cấm. Sau đó hắn dùng bốn loại tứ đại cấm phá giải đồng loạt hàng vạn cấm chế trên boong tàu, biến tất cả thành cấm chế do mình điều khiển, chiếm trọn tầng thứ nhất. Phàn San Mộng ban đầu cười khinh cho rằng Vương Lâm không thể giải nổi nhưng sau đó kinh hoảng khi quyền kiểm soát thuyền bị đoạt dần. Vương Lâm tiến xuống tầng thứ hai, dùng bảy canh giờ phá xong, đoạt thêm quyền kiểm soát — Phàn San Mộng giờ chỉ còn hơn hắn một chút. Bên ngoài, đạo nhân bảy màu đã đánh tan hơn một nửa tầng sáng bảo hộ của thuyền, áp lực thời gian ngày càng tăng."},{"chuong":1603,"tieuDe":"Giả Dối Sao !","tomTat":"Khi Vương Lâm sắp phá xong cấm chế tầng ba chiếm quyền điều khiển thuyền, Phàn San Mộng chủ động mở phòng hộ cho đạo nhân bảy màu đặt chân lên boong tàu tầng một gây sức ép. Vương Lâm không sợ mà hủy luôn cấm chế tầng một cho đối phương tiến vào tầng hai, dùng ngược lại làm đòn bẩy uy hiếp Phàn San Mộng, ép nàng phải trì hoãn đạo nhân bảy màu trong ba canh giờ. Trong thời gian đó hắn nghiên cứu cấm chế tầng ba, tứ đại cấm chế đạt viên mãn chỉ thiếu dung hợp sinh bổn nguyên. Sau hai canh giờ tầng hai sụp đổ, Phàn San Mộng phun máu tươi, Vương Lâm biến cấm chế tầng ba thành lưới chắn rồi cùng nàng tiến vào tầng bốn tràn ngập sương mù. Tại đây Vương Lâm vạch trần nữ tử đồng hành không phải Phàn San Mộng mà là Phàn San Lộ giả dạng bằng cách phun máu biến hóa thần sắc khí tức ngay từ lúc vào thuyền. Hắn tuyên bố toàn bộ cảnh tượng từ tầng hai trở xuống cùng đạo nhân bảy màu trên thuyền đều là huyễn giới do Phàn San Lộ tạo ra, rồi chủ động đánh sập tầng ba, ánh sáng bảy màu bao phủ và thân ảnh đạo nhân bảy màu từng bước đi tới."},{"chuong":1604,"tieuDe":"Huyễn Trung Huyễn","tomTat":"Vương Lâm bị cuốn vào ảo thuật huyễn cảnh song trọng của Phàn San Mộng thi triển từ xa mà không hay biết, toàn bộ cảnh chiến đấu trên thuyền với đạo nhân bảy màu đều là huyễn giới. Trong ảo cảnh hắn bình tĩnh nhận ra tất cả đều là giả, vung tay tiêu tán mọi huyễn tượng và thức tỉnh trên boong tàu tầng nhất. Phàn San Lộ cũng rơi vào ảo thuật của tỷ tỷ mình mà không biết, phun máu tươi khi bị chỉ ra. Vương Lâm phân tích toàn bộ mưu kế tầng tầng lớp lớp của hai chị em Phàn San, suy luận Phàn San Mộng chưa từng chết mà dùng ảo thuật lừa gạt Thất Thải Tiên Tôn, đánh giá nàng là người thứ hai cả đời khiến hắn kiêng kỵ. Hắn hung hăng giật cánh buồm có khuôn mặt quỷ trên thuyền, tuyên bố chiếm bảo vật, khiến Phàn San Mộng ở Tiên Cương đại lục phun máu kinh hãi. Thất Thải Tiên Tôn ở hướng khác trên thuyền cũng đang đắm chìm trong ảo giác nhưng tự nguyện không thoát ra, lý do chỉ mình hắn biết."},{"chuong":1605,"tieuDe":"Quyết Định","tomTat":"Vương Lâm thu tấm buồm mặt quỷ — pháp bảo Đại Hồn Môn, chủ hồn trên thuyền — cùng chiếc thuyền tím làm bồi thường cho việc bị lừa trước đó. Phàn San Lộ trao ngọc giản chứa bản đồ dẫn tới tế đàn và thuật thôn hồn người thứ ba, đồng thời tiết lộ điều kiện mở nội phủ Thất Thải Tiên Tôn: cần hồn thứ ba triệu hồi thiên đạo dẫn đường, nội phủ có cửa thông Tiên Cương đại lục. Nàng chỉ xin Vương Lâm một điều duy nhất: mang nàng về Tiên Cương đại lục, rồi cắn lưỡi phun thệ huyết trao cho hắn. Vương Lâm rời thuyền đi trong tinh không, vừa đi vừa luyện hóa buồm mặt quỷ, tự đánh giá tu vi không bằng bậc toàn năng Không Huyền, cần tận dụng cơ hội tế đàn và đại chiến viễn cổ tiên vực để đề cao tu vi. Thần thức hắn phát hiện đạo nhân bảy màu đang ngồi trên thi hài mãnh thú, toàn thân tỏa sáng bảy màu, chìm đắm trong ảo giác không thể tự kiềm chế. Vương Lâm ném thi hài thăm dò thì bị cấm chế hủy diệt vô thanh trong phạm vi trăm trượng, nhưng vẫn quyết định liều lĩnh tiến vào, thi triển Mộng Đạo thuật cố xâm nhập ảo giác đạo nhân bảy màu. Kết quả thất bại do tu vi đối phương quá cao và cấm chế ngăn cản, Vương Lâm khóe miệng tràn máu nhưng không cam lòng bỏ cuộc."},{"chuong":1606,"tieuDe":"Nguyên Nhân","tomTat":"Vương Lâm phun 99 giọt máu chứa tu vi toàn thân, dung hợp Đạo Cổ bất diệt vào một giọt kèm tia nguyên thần để thâm nhập vùng uy áp kinh khiếp của đạo nhân bảy màu. Giọt máu bị hủy diệt–khôi phục vô số lần, cuối cùng nguyên thần kịp chạm thân đạo nhân. Hắn thi triển Mộng Đạo tiến vào huyễn cảnh bảy màu, phát hiện đạo nhân đang ngồi thẫn thờ trên núi thì thào nhắc tên Phàn San Mộng, suy đoán đây là huyễn trong huyễn. Dùng buồm mặt quỷ tách nguyên thần đột nhập tầng ký ức sâu hơn, chứng kiến đại chiến tại sơn môn Thất Thải Tiên Tôn. Liên Đạo Phi (chính là người điên) cười điên cuồng phá lầu các, phía sau có viêm long đỏ rực và thiếu niên đầu trọc đang chém giết với Thanh Long chiến tướng. Thất Thải Tiên Tôn bị đánh phun máu, phẫn nộ chất vấn Phàn San Mộng và Phàn San Lộ vì sao phản bội, Liên Đạo Phi thừa nhận bị San Mộng câu dẫn, chỉ muốn mảnh vỡ mà Tiên Tôn đạt được. Tiên Tôn triệu hồi Thiên Đạo đồng quy vu tận, thân thể tan nát vỡ thành ba phần: hồn đạo nhân bảy màu, ý cảnh, và trí nhớ hóa cầu vồng. Vương Lâm hiểu ra nguyên nhân đạo nhân bảy màu cam tâm chìm trong ảo giác — hắn đang cố lấy lại phần hồn thứ ba chứa toàn bộ trí nhớ."},{"chuong":1607,"tieuDe":"Rống Chấn Thất Thải","tomTat":"Vương Lâm nhìn thấu mưu kế của đạo nhân bảy màu: lợi dụng ảo giác Phàn San Mộng, dùng tu vi cường hãn sửa lại thành cảnh quay ngược thời gian về lúc thân thể bị phân ba hồn bảy phách, nhằm theo dõi hồn thứ ba tìm nơi luân hồi. Vương Lâm ba lần phun nguyên thần khí tăng tốc gấp trăm lần đuổi kịp đạo nhân bảy màu trong huyễn cảnh tầng hai, tận mắt thấy hồn thứ ba bay vào giới nội rồi xuyên Vân Hải tinh vực hướng Triệu Hà. Nhận ra tu vi không đủ ngăn cản đối phương trong tầng hai, Vương Lâm dùng tấm buồm mặt quỷ thoát về huyễn cảnh tầng một, nơi thân thể thật đạo nhân bảy màu đang ngồi. Bị chín hỏa điểu trong chín vầng mặt trời phóng quang nhiệt ngăn cản, tóc bốc cháy. Vương Lâm nghĩ ra cách đánh thức đạo nhân bảy màu: dùng lục đại bổn nguyên ngưng tụ thành chiếc loa phóng đại âm thanh, kết hợp Đạo cổ lực dung hợp tam tộc cổ, rống một tiếng kinh thiên — thần thông học từ trận đẩy lui Chưởng Tôn ở cổ mộ — khiến thiên không sụp đổ, đại địa nứt vỡ, phong vân biến sắc."},{"chuong":1608,"tieuDe":"Tham Lang Tái Hiện","tomTat":"Vương Lâm dùng lục đại bổn nguyên biến thành loa khuếch đại tiếng rống, xuyên qua chín mặt trời bảo vệ đạo nhân bảy màu, phá tan huyễn cảnh tầng hai nơi hắn đang truy tìm hồn thứ ba. Đạo nhân bảy màu lần đầu tiên tới gần được hồn thứ ba — thấy nó xuyên qua Triệu Hà hướng Côn Hư vạn năm sau — nhưng huyễn cảnh sụp đổ, hồn thứ ba tiêu tán, hắn phẫn nộ thề giết Vương Lâm rồi truy sát. Vương Lâm bị phản kích trọng thương, phun máu gần xương tan thịt nát, nhờ Đạo cổ bất diệt khôi phục, dùng tấm buồm mặt quỷ và huyết độn bỏ trốn hướng tế đàn — nơi hắn đã bói toán qua hồn phách Thiên Vận Tử xác nhận là sinh cơ duy nhất. Sâu trong khe Vân Hải tinh vực, tế đàn bát giác khổng lồ đã tàn phá hiện ra, đỉnh rộng trăm trượng có trận pháp tang thương với cánh tay mười trượng tỏa khí Đạo Cổ ở trung tâm. Qua vết nứt tiếp giáp tế đàn, một không gian kỳ dị dạng đào viên lộ ra. Tham Lang tái hiện trong đào viên đó, khuôn mặt tiều tụy mắt vô thần, bị hai cô bé bí ẩn tên Hàm Hàm và Oa Oa giam giữ suốt trăm năm bắt kể chuyện cổ, cầu xin được tha nhưng bị đề nghị kể thêm ngàn năm nữa."},{"chuong":1609,"tieuDe":"Ký Ức Đau Lòng Hiện Ra","tomTat":"Tham Lang hồi tưởng hành trình sau khi gặp Vương Lâm ở giới ngoại: theo đại quân giới ngoại vào Vân Hải tinh vực, tìm được khe không gian chứa tế đàn Đạo Cổ và thú giới Tử Dương Tông. Hắn xâm nhập thú giới đầy tiên thảo quý hiếm, vây hai tiểu cô nương Oa Oa và Hàm Hàm nhưng bị Oa Oa đá một cước suýt phế tu vi, bị bắt kể chuyện Vương Lâm. Nhân lúc sơ hở, Tham Lang phóng ra khe thì gặp Vương Lâm đang bị đạo nhân bảy màu cùng chín hỏa điểu hóa chín mặt trời truy kích. Vương Lâm phun máu dùng huyết độn lao tới tế đàn, nhận ra cánh tay trên tế đàn thuộc Đạo Cổ Diệp Mịch, nhờ truyền thừa chính tông Đạo Cổ mà dung hợp, cánh tay phát ánh sáng vạn trượng bao phủ toàn thân. Đạo nhân bảy màu tuyên bố muốn luyện hóa thân xác và luyện hồn phách nguyên thần Vương Lâm thành pháp bảo. Tham Lang chui nửa người vào khe cầu cứu, được hai tiểu cô nương truyền tu vi cường hãn, toàn thân tỏa kim quang, hai tay hợp đồ án hình tròn xuất hiện mặt trời màu vàng, lực lượng chấn động tứ đại tinh vực và Thái Cổ Tinh Thần giới ngoại."},{"chuong":1610,"tieuDe":"Bát Tinh Đạo Cổ Hiện Ra","tomTat":"Khí tức cửu dương từ mặt trời mà Tham Lang phóng ra lan khắp tứ đại tinh vực và Tiên Cương đại lục, khiến vô số tu sĩ khiếp sợ, trong đó Phàn San Mộng ở dãy núi đóng băng nhận định đây là khí tức đại thiên tôn. Tử Dương tông lộ diện là tông phái mạnh nhất Cửu Thập Tam Tông, sở hữu đại thiên tôn đang chuyển thế thành hai tiểu cô nương trong tự thú giới. Đạo nhân bảy màu nhận ra khí tức đại thiên tôn, sợ hãi phun máu bỏ chạy, hoàn toàn từ bỏ ý định luyện hóa Vương Lâm. Chiến lão quỷ đang đuổi tứ đại chiến tướng ở La Thiên Tinh Vực cũng chấn động, một giọng nói bí ẩn từ bên trong cơ thể hắn vang lên. Khí tức quét qua vô số sinh linh, vô tình kích thích hồn thứ ba của thất thải bắt đầu thức tỉnh. Vương Lâm nhìn thấy hai tiểu cô nương phong bế cái khe và giấu Tham Lang, nhận ra họ chính là đại thiên tôn chuyển thế, lập chí trở thành đại thiên tôn. Sau đó Vương Lâm chính thức hấp thu dung hợp toàn bộ tám giọt máu Đạo cổ của Diệp Mịch suốt hơn mười ngày, thành công đột phá tam tộc cổ lên Bát Tinh đồng thời: yêu tinh thứ tám, ma tinh thứ tám, tinh điểm Cổ Thần thứ tám đều ngưng thật, hư ảnh Đạo Cổ hiện ra sau lưng, và cảm nhận Tam tổn thất kiếp sắp tới."},{"chuong":1611,"tieuDe":"Cổ Mạch Thương Khung Huyết","tomTat":"Vương Lâm vừa đạt bát tinh Cổ Thần, tam tổn thất kiếp của ba tộc cổ đồng loạt giáng xuống. Hắn lần lượt vượt nhị tổn tứ kiếp Cổ Yêu (một năm mười ngày) và nhị tổn tứ kiếp Cổ Ma (hai mươi ngày), ngưng tụ yêu giáp tím đỏ và ma giáp đen, thân thể Cổ Ma gần đạt đại thành. Tam tộc cổ đều đạt bát tinh cân bằng, 24 tinh điểm đồng chuyển, Đạo cổ hoàn chỉnh — Vương Lâm tự đánh giá đủ sức thắng Không Huyền sơ kỳ. Chương hé lộ cấu trúc đệ tam tổn tam kiếp: Cổ Mạch Thương Khung Huyết (ngưng tụ giọt máu gọi huyết mạch cổ tổ), Cổ Đạo Tam Phân Thần, và Cổ Tổ Chi Tứ. Tiền lệ: Đạo Cổ Diệp Mịch được ba giọt máu, Huyền La Đại Thiên Tôn giữ kỷ lục tám giọt. Vương Lâm bắt đầu kiếp đầu tiên, hòa tan tinh khí thần thành giọt máu; phân thân tu sĩ tách khỏi bổn tôn, bổn tôn hoàn toàn trở thành cổ tộc."},{"chuong":1612,"tieuDe":"Chờ Mong Tại Tiên Cương","tomTat":"Vương Lâm thực hiện nghi thức tạo cổ Mạch Thương Khung Huyết: lần lượt hòa tan thân thể Cổ Yêu, Cổ Ma rồi toàn bộ thân thể Cổ Thần thành ba giọt máu xếp hình chữ phẩm, sau đó dung hợp thành một giọt máu duy nhất màu đen lấp lánh chứa tất cả ba bản nguyên. Khí tức thê lương từ giọt máu xông chín tầng trời, chấn động mọi cổ tộc — Cổ Yêu trong giới nội muốn bái tế, nữ tử Cổ Thần trong Đông Lâm Tinh hoảng sợ nhận ra, Thác Sâm ở giới ngoại đồng tử co rút. Cảnh chuyển sang Tiên Cương đại lục: phía tây bắc là cổ quốc, phía bắc có cổ thành lơ lửng với ngục tù tiên và pho tượng cổ tổ khổng lồ. Huyền La Đại Thiên Tôn — một trong chín mặt trời — đứng trên tay trái pho tượng, tiết lộ đã dùng thuật bói toán tìm ra nguồn gốc cổ Mạch Thương Khung Huyết là người thừa kế Diệp Mịch, tuyên bố sẽ nhận làm đệ tử duy nhất. Cổ hoàng xuất hiện cùng chín người khổng lồ vạn trượng, được trăm vạn tu sĩ kính bái, cung kính gọi Huyền La là tộc thúc. Sau mười ba ngày chờ đợi, mi tâm pho tượng chiếu rọi nửa bầu trời, lần lượt xuất hiện bốn giọt máu gây kinh ngạc toàn thể cổ quốc."},{"chuong":1613,"tieuDe":"Người Đầu Tiên","tomTat":"Trên Tiên Cương đại lục, gần trăm vạn tộc nhân Đạo cổ nhất mạch chứng kiến pho tượng cổ tổ tỏa hồng mang trong nghi thức Cổ Mạch Thương Khung Huyết. Tại tế đàn giới nội, bốn giọt máu cổ tổ từ dòng xoáy khổng lồ lần lượt dung hợp vào giọt máu bổn tôn của Vương Lâm, sinh ra huyết mạch cổ tộc, khiến hắn chính thức trở thành hậu nhân cổ tổ và dân cư cổ quốc. Không cam lòng dừng ở bốn giọt, Vương Lâm chủ động lao vào dòng xoáy sắp tiêu tán — trở thành người đầu tiên trong lịch sử Đạo cổ nhất mạch làm vậy — đoạt thêm giọt năm, sáu, bảy, rồi tám, ngang bằng kỷ lục của Huyền La Đại Thiên Tôn năm xưa. Huyền La ngửa mặt cười to trước kết quả này. Hoàng tôn Đạo cổ nhất mạch (Cổ Hoàng), người năm đó đạt sáu giọt và tự coi mình là thiên tài chính thống, từ đầu khinh thường rồi dần xanh mét khi bị vượt qua, cực lực đè nén ghen ghét, giữ vẻ tươi cười bên ngoài nhưng trong lòng âm trầm bất mãn."},{"chuong":1614,"tieuDe":"Hoàng Tôn Đố Kỵ","tomTat":"Vương Lâm không chấp nhận chỉ bốn giọt máu cổ tổ, lao thẳng vào dòng xoáy đang sắp tiêu tán, thách thức cổ tổ và đặt điều kiện ngược: phải cho nhiều máu và cơ duyên hơn, nếu không hắn sẽ bức bỏ huyết mạch cổ và nhập tiên tộc. Hắn dùng ánh sáng trắng sữa trên mi tâm huyễn hóa hình ảnh quá khứ — cảnh đạt truyền thừa ký ức Đồ Ti trên Chu Tước Tinh và cảnh ở cổ mộ Thái Cổ Tinh Thần — chứng minh sớm có truyền thừa Cổ Thần. Thần thức cổ tổ kiểm chứng xong rút đi, dòng xoáy ngưng tụ trở lại, giọt máu tăng từ năm lên chín rồi xuất hiện giọt thứ mười màu tím — hồn huyết cổ tổ, chưa từng có tiền lệ từ cổ chí kim. Tại thành trì Đạo cổ nhất mạch, hoàng tôn hoàng bào lần đầu lộ vẻ khiếp sợ rồi ghen ghét đạt đỉnh điểm, ngoài mặt chúc mừng nhưng ngầm ám chỉ Vương Lâm có thể trở thành tân Đại Thiên Tôn nhằm gây nghi kỵ, bị Huyền La Đại Thiên Tôn nhìn xuyên thấu và cảnh cáo. Huyền La dùng lực lượng Huyền Dương triệu mặt trời đỏ phong bế thiên địa, hạ sắc lệnh giết bất kể ai tiết lộ chuyện hồn huyết, rồi quyết định đích thân tới chỗ tiên tộc đón Vương Lâm về."},{"chuong":1615,"tieuDe":"Một Tia Hồn Phách","tomTat":"Năm giọt máu tươi và một giọt hồn huyết màu tím — kết quả tam tổn đệ nhất kiếp — bay từ pho tượng cổ tổ vào dòng xoáy trên trời, gần trăm vạn tộc nhân Đạo cổ chứng kiến kinh hoàng vì đây là giọt thứ mười, vạn đời chỉ có chín. Huyền La Đại Thiên Tôn phân hóa mặt trời đỏ thành gần trăm vạn phần dung nhập vào tộc nhân để phong ấn tin tức, rồi bước một bước biến mất, đích thân tới Thất Đạo Tông ở tiên tộc đón Vương Lâm về. Hoàng tôn Đạo cổ trở về hoàng cung trong Thiên Không Chi Thành, phẫn nộ phá hủy hành cung giết thị vệ, tuyên bố mình mới là hậu nhân chính thống cổ tổ, coi thường Vương Lâm. Hoàng tôn triệu Diệp Đạo hỏi về nữ tử có phân hồn trong hạt châu đỏ do quốc sư giao — tra khắp cổ quốc không thấy, đang phái người sang tiên tộc. Diệp Đạo thuật lời tiên tri quốc sư trước khi bế quan: hai hình ảnh bất động — hoàng tôn thống nhất cổ quốc hoặc tử vong, cả hai đều có thân ảnh người tóc bạc mơ hồ. Tại cái khe Vân Hải tinh vực, dòng xoáy khổng lồ xuất hiện huyết quang chiếu lên Vương Lâm khiến trông như huyết nhân, vài giọt máu tươi từ dòng xoáy gào thét lao ra."},{"chuong":1616,"tieuDe":"Cổ Đạo Nghịch","tomTat":"Vương Lâm tiếp nhận giọt máu tươi thứ 5 đến thứ 9 của Cổ Tổ qua mi tâm, cốt tủy thay đổi hoàn toàn, huyết mạch đạt nồng đậm ngang hoàng tôn Đạo cổ, trở thành đệ nhất huyết mạch trong Đạo cổ nhất mạch. Tiếp đó giọt hồn huyết màu tím dung nhập mi tâm, biến đổi hồn phách khiến Vương Lâm tương đương con trai thứ tư Cổ Tổ, cao quý hơn hoàng tôn. Trong lúc hôn mê trên tế đàn, Vương Lâm mộng thấy Cổ Tổ — vị thủy tổ cổ tộc sinh trước thiên địa — tuyên bố ý chí nghịch tiên và truyền khẩu quyết cho hậu nhân. Tỉnh dậy, tám tinh điểm Cổ Thần trên mi tâm chuyển tím, khí tức trở nên ngạo nghễ bá đạo. Vương Lâm dung hợp hoàn toàn cánh tay Diệp Mịch vào tay phải bằng 24 tinh điểm phát ánh sáng tím, tay phải biến đổi thô ráp với ký hiệu phức tạp và vẻ xanh mét. Hắn lần đầu thi triển thuật Tê Thiên bằng tay phải mới, xé mở khe khổng lồ trong tinh không với uy lực đủ giết tu sĩ Không Huyền sơ kỳ. Cuối cùng Vương Lâm phát hiện tế đàn ẩn chứa điều cổ quái."},{"chuong":1617,"tieuDe":"Tam Mệnh Thuật","tomTat":"Vương Lâm dung hợp phân thân trở lại bổn tôn sau khi thu nạp cánh tay Diệp Mịch và hồn huyết Cổ Tổ. Hắn dùng gần trăm vạn cấm chế phá vỡ tế đàn đá, phát hiện bên trong ẩn giấu vật hình bát giác tỏa hồng quang — phần tế đàn thứ ba và cuối cùng của Phong Diệt Tộc. Kết hợp Tê Thiên toàn lực (cánh tay Diệp Mịch cùng lực lượng Cổ Thần, Cổ Yêu, Cổ Ma bát tinh) xé nát hồng vân và phá hủy hoàn toàn tế đàn. Ba phần tế đàn Phong Diệt Tộc (huyết các Huyết Tổ từ Côn Hư, tế đàn từ Cổ Yêu ở La Thiên, vật bát giác vừa phát hiện) đồng thời xuất hiện, huyết quang giao hòa xác nhận cùng nguồn gốc. Vương Lâm ấn tộc ấn Phong Diệt Tộc vào mi tâm, phun máu tươi niệm chú gọi tổ linh, máu hóa trường đao ba thanh chồng nhau, bắt đầu tu luyện Tam Mệnh Thuật. Thực hiện bước Trảm Tam Hồn — trường đao chém xuyên thân thể, trảm được tam hồn nhưng linh hồn quá cường đại (dung hợp hồn huyết Cổ Tổ) khiến đao chịu không nổi lực phản chấn, tan nát tiêu tán."},{"chuong":1618,"tieuDe":"Trảm Tam Thân","tomTat":"Vương Lâm dùng đôi trường đao cùng lực lượng kỳ dị của Phong Diệt Tộc thực hiện Trảm Tam Thân, chia thân thể, hồn phách và nguyên thần làm ba phần, nhập vào ba tế đàn. Sau chín ngày huyết quang biến mất, ba Vương Lâm xuất hiện từ tế đàn sụp đổ rồi dung hợp lại thành một, hoàn thành Tam Mệnh Thuật — từ nay có ba mạng sống, nhưng tế đàn đã bị phá hủy nên không thể dùng lại. Hắn giải phóng hồn phách nữ tử cố nhân trong huyết các, tuyên bố ân oán xóa bỏ, tiễn nàng vào luân hồi. Vương Lâm xác nhận thân thể đạt huyết mạch Đạo cổ, yêu, ma, thần đạt bát tinh, rồi lên kế hoạch luyện hóa buồm mặt quỷ để sinh cấm chế bổn nguyên thứ bảy nhằm đột phá Không Linh hậu kỳ, đồng thời nghiên cứu huyễn đạo Đại Hồn Môn để tìm hồn thứ ba. Hắn đột ngột nhớ tới Thiên Vận Tử — người đạt máu thiên đạo, không chết, ẩn thế suốt đại chiến, có hơn ba nghìn phân thân — và nghi ngờ Thiên Vận Tử chính là hồn thứ ba của Thất Thải Tiên Tôn. Cuối cùng hắn dùng huyết kiếm chém xuyên buồm mặt quỷ, đưa thần thức vào bên trong, cấm chế tràn ra bao phủ toàn bộ khe Vân Hải tinh vực, bắt đầu quá trình dung hợp."},{"chuong":1619,"tieuDe":"Cấm Chế Bổn Nguyên","tomTat":"Vương Lâm ngồi trong khe nứt Vân Hải tinh vực dùng thần thức Không Linh trung kỳ tính toán dung hợp cấm chế bổn nguyên. Cơn lốc cấm chế khiến mãnh thú trong khe bỏ chạy tạo hiện tượng thú triều, bên ngoài nhiều tu sĩ chú ý nhưng không dám vào. Vương Lâm minh ngộ bản chất cấm chế chính là trận pháp, là đại đạo, là quy tắc thiên địa — bổn nguyên cấm chế là lực lượng tính toán bao trùm La Thiên, có thể tính toán tương lai và thay đổi vận mệnh. Hắn nhận định Thiên Vận Tử đã ẩn giấu trình độ cấm chế kinh thiên. Qua chín lần dung hợp liên tiếp: ba lần đầu bằng thần thức thuần, lần bốn triệu bổn tôn tách khỏi phân thân hóa tam thể Cổ Yêu, Cổ Ma, Cổ Thần đè nén cấm chế, lần năm đến tám dùng lục đạo bổn nguyên hóa sáu kiếm áp chế, lần chín phun máu tươi chia 3172 phần thi triển Huyết cấm. Từ vô số cấm chế dung hợp còn chín cái lớn ngàn trượng nhưng hai cái lập tức vỡ tung. Vương Lâm điểm chỉ vào mắt phải, phun sương mù máu biến ảo thành hư ảnh đồng tử khổng lồ tràn ngập tơ máu, chương kết thúc cliffhanger."},{"chuong":1620,"tieuDe":"Mộc Ti Như Tắc","tomTat":"Vương Lâm suy ngẫm bản chất quy tắc, pháp tắc và cấm chế, nhận ra cấm chế là sinh linh thượng cổ bắt chước quy tắc thiên địa tạo ra. Hắn chọn phương pháp dùng tơ máu đồng tử hai mắt làm sợi tơ quy tắc, dung hợp toàn bộ cấm chế xung quanh — phương pháp từ cổ chí kim chưa ai nghĩ tới. Hai đồng tử hư ảo khổng lồ xuất hiện hấp thu mọi cấm chế, tam thể bổn tôn và phân thân dung hợp thành một, đạo bổn nguyên thứ bảy thành hình. Tơ máu ngưng tụ thành sợi chỉ hồng chia đôi đồng tử, thanh kiếm cấm chế hư ảo xuất hiện, tu vi từ Không Linh trung kỳ trực tiếp đột phá lên Không Linh hậu kỳ. Hắn thử gảy sợi dây quy tắc vô hình tạo ra vùng băng hàn và hố đen, thu tấm buồm mặt quỷ — lỗ hổng tự khép lại nguyên vẹn, hoàn toàn trở thành bảo vật. Hắn tổng kết chuyến Vân Hải tinh vực với thu hoạch lớn: tu vi tăng, được buồm và thuyền, liên minh Phàn San Lộ, mơ hồ thấy phương pháp tìm hồn thứ ba. Cùng lúc tại phạm vi tiên tộc Tiên Cương đại lục, Huyền La Đại Thiên Tôn giao chiến ầm ầm trên chín tầng trời với tu sĩ Đạo Nhất Tông, bị nhận định sắp chuyển thế tu vi yếu đi, đe dọa diệt cả Đạo Nhất Tông nếu bị ngăn trở."},{"chuong":1621,"tieuDe":"Tính Thiên Vận Tử","tomTat":"Vương Lâm rời khe núi Vân Hải tinh vực, tới ranh giới tân tiên giới dùng tơ máu trong đồng tử và quy tắc tinh không tăng cường cấm chế bảo vệ tiên giới. Hắn bước vào tiên giới, được Hồng Sam Tử, Thanh Lâm, Thanh Thủy, Tư Đồ Nam, Nam Vân Tử cùng nhiều người quen nghênh đón. Hồng Điệp đã nhận cha Thanh Thủy, Chu Dật u buồn nhìn Thanh Sương từ xa. Vương Lâm ở đỉnh núi phía bắc hơn một tháng, trả hồn huyết giải phong ấn cho Đầu to, giao toàn bộ tiên thuật Lôi Tiên Giới cho Thanh Lâm truyền thụ, nghiên cứu tấm buồm mặt quỷ Cấm Phiên nhưng tiến triển chậm. Bên ngoài đại loạn bắt đầu — tứ đại chiến tướng viễn cổ tiên vực dùng trận pháp huyết mạch tiên nhân tìm hồn thứ ba, Đạo nhân bảy màu triệu tập Chưởng Tôn hướng Côn Hư, Chiến lão quỷ chỉ quan sát không hành động. Vương Lâm nhớ Lý Mộ Uyển cảm thấy có lỗi, ghé khu Lam Ti tộc biết Lý Thiến Mai đang bế quan. Cuối cùng hắn coi Thiên Vận Tử là cái gai phải rút, tiến vào hồn Thiên Vận Tử hắn nắm giữ để truy tìm bổn tôn quyết tâm giết."},{"chuong":1622,"tieuDe":"Thiên Vận Tử","tomTat":"Vương Lâm ngồi trong nhà tranh trên đỉnh núi tân tiên giới, tập trung dung hợp với hồn phách phân thân Thiên Vận Tử nhằm truy tìm vị trí bổn tôn. Cùng lúc, bổn tôn Thiên Vận Tử ngồi trên thiên thạch trong Triệu Hà, cảm ứng được liên kết và lần lượt thể hiện sáu bổn nguyên đã có: Nhân Quả, Sinh Tử, Chân Giả, hỏa, lôi, Sát Lục. Hắn nói đã thu được bổn nguyên thứ bảy là cấm chế bổn nguyên — phương pháp Vương Lâm sáng tạo, đang thông qua liên kết phân thân để lĩnh ngộ. Thiên Vận Tử gọi Vương Lâm là đồ nhi mà hắn bỏ hai ngàn năm tính toán, nói cái cây đã khai hoa nhưng chưa tới ngày hái quả. Sau năm ngày dung hợp, Vương Lâm đột ngột cảm thấy bổn nguyên dường như bị mất đi dù kiểm tra không giảm, thử lần hai vẫn bất ổn, dứt khoát tách ra và nghi ngờ toàn bộ việc năm xưa giết phân thân ở vùng đất yêu linh đều nằm trong âm mưu Thiên Vận Tử. Vương Lâm rút hồn phách phân thân, dịch chuyển tới tuyết sơn phía nam tiên giới tìm Thanh Lâm. Trên sườn núi, Thanh Sương đang gắng nhớ lại ký ức bên cạnh Chu Dật. Thanh Lâm xưng Vương huynh thay vì gọi đệ tử như trước, tiếp nhận hồn phách Thiên Vận Tử để ngưng thần quan sát và tính toán."},{"chuong":1623,"tieuDe":"Luân Hồi Nhất Thể","tomTat":"Thanh Lâm kiểm tra phân hồn Thiên Vận Tử do Vương Lâm nắm giữ, xác nhận cực yếu không có mánh khóe. Vương Lâm để Thanh Lâm dung nhập thần thức vào cơ thể mình quan sát bổn nguyên khi dung hợp phân hồn — Thanh Lâm kinh hoàng phát hiện Vương Lâm có bảy đạo bổn nguyên (trước chỉ biết sáu) và lực lượng huyết mạch cổ xưa bá đạo không phải Cổ Thần thông thường. Khi dung hợp sâu, cấm chế bổn nguyên Vương Lâm tự phân ra một tia vận chuyển dị thường mà hắn không biết, Thanh Lâm dùng Định Thần Thuật ngăn kịp rồi rút sợi tơ u quang truy tìm đầu mối, bị kéo vào Triệu Hà tinh vực và bị đạo nhân bảy màu dùng lưỡi hái bảy màu khổng lồ tấn công. Thanh Lâm dùng Tam quang hộ thể tam kiếm khai hà phá vỡ lưỡi hái nhưng bị chấn, quay về tuyết sơn. Lam Mộng Đạo Tôn xuất hiện, tiết lộ Thiên Vận Tử đang dùng Luân Hồi nhất thể thuật — thần thông của Thất Thải Tiên Tôn (chưa tu thành), qua vô số luân hồi tạo phân thân cắn nuốt nhau, có thể trộm toàn bộ bổn nguyên tu vi kẻ dung hợp phân thân. Lam Mộng Đạo Tôn đánh giá Vương Lâm nắm chắc bốn phần đã mắc thuật, nhưng nếu giết được đối phương thì ngược lại sẽ thôn phệ tăng tu vi. Lam Mộng Đạo Tôn dùng lam quang giúp Vương Lâm nhìn thấy bổn tôn Thiên Vận Tử đang ở trên viên thiên thạch sâu trong Triệu Hà tinh vực, ánh mắt hai người chồng lên nhau."},{"chuong":1624,"tieuDe":"Quỷ Dị","tomTat":"Vương Lâm nhận ra âm mưu của Thiên Vận Tử, vọt khỏi tiên giới ra tinh không truy sát. Thanh Lâm truyền thần niệm kêu gọi Hồng Sam Tử đuổi theo, Lam Mộng Đạo Tôn lộ sát khí cũng rời đi, Nam Vân Tử ở lại trấn giữ tiên giới. Vương Lâm dung nhập thiên địa tới Triệu Hà, phá nát thiên thạch tìm thấy Thiên Vận Tử. Hai bên đại chiến bằng hỏa bổn nguyên (hỏa Chu Tước đối kháng) và lôi bổn nguyên (chín Lôi Long đấu lôi điện khai thiên), cận chiến nắm quyền khiến Vương Lâm phun máu. Vương Lâm thi triển chiêu mới Sát cấm — dùng tơ máu đồng tử tạo cấm chế chia lìa thân thể Thiên Vận Tử. Thiên Vận Tử cười quỷ dị, nói hai người đã thành một thể, hồn phách tự dung nhập vào Vương Lâm. Trên tu chân tinh khô héo, Thiên Vận Tử đã đoạt được cấm chế bổn nguyên từ lần đối chiến trước, chủ động tự sát lần hai, phân hồn lại nhập vào Vương Lâm. Hắn tiết lộ Luân Hồi Toàn Thể Thuật và sự thật đã tỉnh giấc 98 lần, chỉ hướng phân thân tiếp theo dẫn dụ Vương Lâm tiếp tục đuổi theo."},{"chuong":1625,"tieuDe":"Thiên Vận Tử Ngươi Có Thể Sao","tomTat":"Vương Lâm đứng trên tu chân tinh cảm nhận khí tức Thiên Vận Tử, bình tĩnh phân tích âm mưu đoạt xá và cơ chế Luân Hồi toàn thể thuật, suy luận hắn không phải nạn nhân đầu tiên. Hắn chủ động tìm đến đám đá vụn trong Triệu Hà tinh vực đối mặt phân thân Thiên Vận Tử, bình thản ngồi khoanh chân đối thoại. Thiên Vận Tử tặng thủy bổn nguyên (một tia trộm từ người khác) và thổ bổn nguyên (đám bùn đất sống) cho Vương Lâm, đề xuất trò chơi đã bắt đầu từ nhiều năm trước. Khi Thiên Vận Tử định diễn cảnh tử vong quỷ dị bằng cách tự điểm mi tâm lần hai, Vương Lâm dùng cuồng phong huyết mạch Đạo cổ cản lại và vạch trần mọi sự thần bí chỉ là vờ vịt. Vương Lâm phát hiện sơ hở trí mạng: Thiên Vận Tử không có khí tức Đạo cổ, Luân Hồi toàn thể thuật không trộm nổi huyết mạch Đạo cổ. Hắn khẳng định Thiên Vận Tử hiện tại chỉ là phân thân, bổn tôn ở nơi khác. Vương Lâm tuyên bố tự đặt quy tắc trò chơi: bổn tôn hắn sẽ đi tìm bổn tôn Thiên Vận Tử mà giết, phân thân tu sĩ chỉ là con cờ. Cuối cùng hắn phóng lực lượng Đạo cổ tấn công phân thân Thiên Vận Tử."},{"chuong":1626,"tieuDe":"Thiên Vận Tử Trúng Kế","tomTat":"Vương Lâm tách bổn tôn khỏi phân thân, chủ động phế bỏ phân thân để Tam Mệnh Thuật tử vong một lần, hủy mưu kế trộm thần thông của Thiên Vận Tử. Hồn Phiên hóa sương mù, hơn phân nửa nhập mi tâm bổn tôn, phần còn lại bao phủ thân bổn tôn để bảo vệ. Hắn thu hồi hai bổn nguyên, biến hồn phách phân thân thành dạng thôn hồn, rồi giao bổn tôn cho Lam Mộng Đạo Tôn, Thanh Lâm và Hồng Sam Tử hộ pháp. Thiên Vận Tử ở phía đông Triệu Hà, tự tin bổn tôn không thể bị tìm vì chính hắn cũng đã quên vị trí, nhưng lo ngại quỷ kế Vương Lâm nên đồng loạt triệu gần ba nghìn phân thân trong tứ đại tinh vực. Hồn phách Thiên Vận Tử trong cơ thể Vương Lâm lập tức sôi trào liên lạc toàn bộ phân thân — Vương Lâm cảm ứng vị trí từng phân thân, dùng Mộng Đạo làm đường kết hợp cấm chế Hồn Phiên mộng nhập ba nghìn phân thân truy tìm bổn tôn. Bổn tôn Vương Lâm mở bừng mắt, nhập huyễn cảnh ngàn năm trước, thấy Thiên Vận Tử ngồi trên thiên thạch Triệu Hà xưa tay dính máu thiên đạo cướp từ Thanh Long Thánh Hoàng, rồi há miệng cắn nuốt Lăng Thiên Hầu đang hôn mê. Thiên Vận Tử thức tỉnh, xác nhận đã chuẩn bị cho lần ngủ-thức tỉnh tiếp theo với đối tượng là Vương Lâm, huyễn cảnh tiêu tán rồi lập tức hóa ra hình ảnh mới."},{"chuong":1627,"tieuDe":"Thân Phận Của Hắn","tomTat":"Vương Lâm tiếp tục chứng kiến luân hồi của Thiên Vận Tử, lần ngược thời gian từ hiện tại về thái cổ rồi tới tinh vực tử vong — thời điểm ban đầu của thế giới trong động phủ khi chưa có sinh mạng. Qua đó phát hiện sự thật chấn động: Thiên Vận Tử không phải tam hồn thất phách của Thất Thải Tiên Tôn mà là một thực thể nguyên thủy cổ xưa hơn, đã nuốt phách nguyên thủy và thất phách của Thất Thải Tiên Tôn để trưởng thành, mục đích cuối cùng là mạo danh Thất Thải Tiên Tôn hoàn chỉnh và nắm luân hồi. Đồng thời hé lộ nguồn gốc quan hệ sư đồ giả: Thiên Vận Tử chủ động tìm thấy Vương Lâm trên tu chân tinh bỏ đi khi hắn mới tu vi Nguyên Anh, nhận đệ tử ký danh với mục đích bồi dưỡng rồi cắn nuốt phân thân. Ở hiện tại, gần ba nghìn phân thân Thiên Vận Tử trên tứ đại tinh vực đồng loạt tự hủy, hồn phách hợp nhất xông vào phân thân Vương Lâm ở Triệu Hà để đoạt xác, tuyên bố đây là lần ngủ say cuối cùng sẽ hoàn thành kế hoạch luân hồi vạn cổ. Phân thân Vương Lâm bình tĩnh khoanh chân ngồi không phản kháng dù hồn phách đã mơ hồ chiếm toàn bộ thân thể. Chương kết ở câu mở: Vương Lâm đã nhận ra thân phận thật của đối phương nhưng chưa nói ra."},{"chuong":1628,"tieuDe":"Thiên Đạo","tomTat":"Bổn tôn Vương Lâm đắm chìm trong luân hồi Thiên Vận Tử, phát hiện sự thật kinh thiên: Thiên Đạo mà vô số người tìm kiếm chính là Thiên Vận Tử, bổn tôn là nửa nghịch la bàn mang ấn ký cổ xưa nằm sâu trong một tu chân tinh không sinh mạng. Trong luân hồi, hắn chứng kiến cánh cửa khổng lồ (khác cánh cửa Thiên Nghịch) bị lực lượng cường đại oanh kích vỡ tung, đám sương mù bạc chia hai — phần lớn chứa bóng tiên nhân gào thét bay biến mất, phần nhỏ chứa nửa nghịch la bàn rơi vào tu chân tinh. Thiên đạo vốn không linh trí, sau khi cắn nuốt tiên nhân Liên Đạo Phi và hấp thu phần thần thức tự bạo cùng tham lam tính xấu mà sinh ra suy nghĩ, hóa hình thanh niên. Vương Lâm ngộ ra chân tướng Liên Đạo Phi: bị tách phần tính xấu nên thành người điên hiện tại, hoàn toàn khác kẻ ngỗ ngược kiêu ngạo năm xưa. Mảnh cánh cửa vỡ xuyên tới Côn Hư tạo khe không gian, sau được tu sĩ Tứ Thánh Tông na di tu chân tinh che giấu, khe này trở thành chiến trường ngoại vực. Thoát luân hồi, Vương Lâm cảm nhận phân thân sắp bị hồn phách Thiên Vận Tử chiếm cứ hoàn toàn, nhờ Lam Mộng Đạo Tôn, Thanh Lâm, Hồng Sam Tử khống chế phân thân, rồi lên đường tìm bổn tôn Thiên Vận Tử."},{"chuong":1629,"tieuDe":"Bổn Tôn Của Thiên Vận Tử","tomTat":"Bổn tôn Đạo cổ của Vương Lâm xé khe tinh không di chuyển từ Triệu Hà tới Côn Hư tinh vực chỉ trong gần một nhịp thở, phương pháp cực kỳ nguy hiểm mà chỉ thân thể Đạo cổ có huyết mạch mạnh hơn Cổ Thần mới chịu nổi. Cùng lúc ở Triệu Hà, hồn phách Thiên Vận Tử từ tứ đại tinh vực hội tụ chiếm cứ phân thân Vương Lâm qua Luân Hồi nhất thể thuật, phân thân biến hình thành Thiên Vận Tử đầu tóc bạc phơ, hoàn thành lần thức tỉnh thứ 99 và tự xưng mình là thiên đạo. Tại Côn Hư, Vương Lâm phát hiện tu chân tinh hoang dã mang khí tức tinh hồn quen thuộc, xuyên xuống đáy biển đen vào động cổ vạn cổ, đoạt lấy nửa cái la bàn chôn vùi trong bụi đất — chính là bổn tôn thật sự của Thiên Vận Tử. Thiên Vận Tử toan rời đi nhưng bị Lam Mộng Đạo Tôn chặn trước mặt theo lời hứa với Vương Lâm, Thanh Lâm và Hồng Sam Tử cùng áp sát, giao chiến ngắn với sương mù vô tận của Thiên Vận Tử. Cuối chương, giọng nói lạnh băng đầy sát khí của Vương Lâm vang tới từ cuối tinh không, tuyên bố đã đem bổn tôn của Thiên Vận Tử về."},{"chuong":1630,"tieuDe":"Tư Cách Trục Lộc","tomTat":"Vương Lâm bạch y tóc bạc xuất hiện cầm nửa la bàn — bổn tôn của Thiên Vận Tử — khiến hắn kinh hoàng tột cùng. Thiên Vận Tử thi triển Thiên đạo nhất thể triệu hồi miệng khổng lồ nhưng thất bại, rồi đánh lui Lam Mộng Đạo Tôn và áp sát Vương Lâm. Vương Lâm bình tĩnh kích hoạt ấn ký trên ngực phân thân, lần lượt tiêu hủy bảy đạo bổn nguyên, nguyên thần, hồn phách — phá vỡ sự dung hợp ba nghìn phân thân của Thiên Vận Tử, khiến 2999 hồn phách nổ tung. Vương Lâm tự xưng là chủ nhân của thiên đạo, điểm mi tâm khiến tinh điểm Cổ Thần tiêu tán, triệu hồi U Minh Thú từ dòng xoáy bên trong. Cho nửa la bàn bay vào miệng U Minh Thú rồi ra lệnh nuốt sạch toàn bộ 2999 hồn phách đang bỏ chạy. Vương Lâm từ biệt Lam Mộng Đạo Tôn, Thanh Lâm, Hồng Sam Tử, nhờ nhắn Thanh Thủy sư huynh đừng ra ngoài và chờ hắn trở về, rồi ngồi lên lưng U Minh Thú bay đi — chính thức có tư cách trục lộc trong thế giới động phủ."},{"chuong":1631,"tieuDe":"Ngưng Tụ Bổn Nguyên","tomTat":"Vương Lâm cưỡi u Minh thú thu nhỏ còn ngàn trượng lao đi trong tinh không, hồi tưởng về trận đấu với Thiên Vận Tử và ngộ ra u Minh thú cùng Thiên Vận Tử đều là bộ phận của thiên đạo, tuyên bố mình đã trở thành chủ nhân thiên đạo. Hắn nhớ lại Thất Thải Tiên Tôn năm xưa đạt được mảnh nhỏ chứa thiên đạo và Thiên Nghịch, từ đó mới có la bàn, và nhiều người gồm Đạo nhân bảy màu, Chiến lão quỷ đều nhắm tới thiên đạo. Vương Lâm phun máu Đạo cổ huyết mạch ngưng tụ phân thân mới, dùng tinh điểm tam tộc rút lực Đạo cổ, tách hồn phách vào phân thân rồi bổn tôn ngủ say để phân thân tiếp quản. Phân thân lần lượt thu hồi bốn đạo bổn nguyên đã tiêu tán: Hỏa bổn nguyên vào mắt trái, Lôi bổn nguyên vào mắt phải, Sinh Tử bổn nguyên dung hợp thành vòng âm dương ở mi tâm khiến khí tức bạo tăng, Chân Giả bổn nguyên khiến thân hóa hư ảo. Trong lúc đó u Minh thú đã đưa hắn tới Triệu Hà tinh vực, nơi tứ đại chiến tướng viễn cổ tiên vực dẫn hơn trăm tiên nhân đang dùng hồ lô xanh biếc cổ xưa truy tìm mục tiêu, Chiến lão quỷ mặc đạo bào thong dong theo sau nhưng hai bên lờ nhau."},{"chuong":1632,"tieuDe":"Ngăn Trở","tomTat":"U Minh thú sau khi dung hợp với Thiên Vận Tử trở thành thiên đạo, có khả năng ẩn hình tuyệt đối khiến thần thức của tứ đại chiến tướng và Chiến lão quỷ đều không phát hiện nổi. Bổn tôn Vương Lâm ngủ say khôi phục trên lưng U Minh thú, phân thân ngưng tụ bảy đại bổn nguyên rồi dung hợp với bổn tôn thành một thể hoàn chỉnh. Vương Lâm xác định mục tiêu tiếp theo là tới Ngũ Hành tinh bức lực lượng ẩn thế cuối cùng lộ diện, sau đó triển khai trận tranh đoạt hồn thứ ba, coi Thiên Vận Tử là cây đinh đã rút và Quy Nguyên Tông là cây đinh thứ hai. Khi U Minh thú di chuyển sâu vào Vân Hải tinh vực, bị tứ đại chiến tướng cùng Chiến lão quỷ và hơn trăm tiên nhân chặn đường bao vây, đòi biết nguồn gốc U Minh thú hoặc cho mượn, uy hiếp sẽ chấm dứt hợp tác. Vương Lâm bình thản không nao núng, tuyên bố cho bọn họ nếm đau đớn tới tận xương cốt rồi triệu hoán Khai Thiên Phủ khổng lồ đối đầu."}];
